class AWSResource:
    def __init__(self, id, regione, tipo):
        self.id      = id
        self.regione = regione
        self.tipo    = tipo
    def costo_mensile(self):
        raise NotImplementedError

class EC2(AWSResource):
    def __init__(self, id, regione, prezzo_ora):
        super().__init__(id, regione, "EC2")
        self.prezzo_ora = prezzo_ora
    def costo_mensile(self):
        return round(self.prezzo_ora * 730, 2)

class S3Bucket(AWSResource):
    def __init__(self, id, regione, gb):
        super().__init__(id, regione, "S3")
        self.gb = gb
    def costo_mensile(self):
        return round(self.gb * 0.023, 2)

